import{_ as t,o as i,c as o,ae as r}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"NeoClouds Provider Overview","description":"","frontmatter":{},"headers":[],"relativePath":"neoclouds/index.md","filePath":"neoclouds/index.md"}'),a={name:"neoclouds/index.md"};function n(s,e,l,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="neoclouds-provider-overview" tabindex="-1">NeoClouds Provider Overview <a class="header-anchor" href="#neoclouds-provider-overview" aria-label="Permalink to &quot;NeoClouds Provider Overview&quot;">​</a></h1><p>The hybridai-NVFP4 TUI application integrates with specialized GPU cloud providers (Neo-Clouds) via APIs/SDKs to provision transient computing power optimized for NVFP4 workloads on Blackwell architecture GPUs.</p><p>These providers offer GPU-optimized infrastructure with flexible pricing models, ideal for the &quot;one-off&quot; high-compute tasks that the hybridai-NVFP4 system is designed to handle.</p><h2 id="provider-comparison" tabindex="-1">Provider Comparison <a class="header-anchor" href="#provider-comparison" aria-label="Permalink to &quot;Provider Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Website</th><th>Primary Integration</th><th>Best For</th><th>Typical GPU Offerings</th></tr></thead><tbody><tr><td><strong>Modal</strong></td><td>modal.com</td><td>SDK/API</td><td>Serverless, bursty workloads</td><td>H100, A100, L40S, custom GPU tiers</td></tr><tr><td><strong>SimplePod</strong></td><td>simplepod.com</td><td>Kubernetes pods</td><td>Predictable, sustained loads</td><td>H100, H200, Blackwell GPUs</td></tr><tr><td><strong>Verda</strong></td><td>verda.com</td><td>REST API instances</td><td>Low-latency, interactive use</td><td>H100, HGX H100, custom configurations</td></tr><tr><td><strong>Nebius</strong></td><td>nebius.com</td><td>Cloud platform</td><td>Enterprise, scalable deployments</td><td>H100, B200, custom GPU clusters</td></tr></tbody></table><h2 id="core-requirements-across-all-platforms" tabindex="-1">Core Requirements Across All Platforms <a class="header-anchor" href="#core-requirements-across-all-platforms" aria-label="Permalink to &quot;Core Requirements Across All Platforms&quot;">​</a></h2><p>To successfully deploy Nemotron 3 Super in NVFP4 format on any NeoCloud provider, ensure the following:</p><ol><li><p><strong>Blackwell GPU Architecture Support</strong> (sm_100 compute capability)</p><ul><li>Required for native NVFP4 support</li><li>Look for instances mentioning Blackwell, B200, B300, GB200, GB300, or DGX Spark</li></ul></li><li><p><strong>CUDA Version 12.9+ or 13.x</strong></p><ul><li>Essential for NVFP4 quantization and inference</li><li>Verify in provider documentation or instance specifications</li></ul></li><li><p><strong>Docker with NVIDIA Container Toolkit</strong></p><ul><li>Required for containerized deployment of inference engines</li><li>Most GPU-focused providers include this by default</li></ul></li><li><p><strong>High-Bandwidth Networking &amp; Storage</strong></p><ul><li>NVMe storage recommended for model caching (~200GB+)</li><li>Sufficient network bandwidth for multi-GPU communication if using tensor parallelism</li></ul></li><li><p><strong>Flexible Instance Lifecycle Management</strong></p><ul><li>Ability to start/stop instances on demand</li><li>Support for spot/preemptible instances for cost optimization</li><li>API/SDK provisioning for automation</li></ul></li></ol><h2 id="cost-optimization-strategies" tabindex="-1">Cost Optimization Strategies <a class="header-anchor" href="#cost-optimization-strategies" aria-label="Permalink to &quot;Cost Optimization Strategies&quot;">​</a></h2><h3 id="spot-preemptible-instances" tabindex="-1">Spot/Preemptible Instances <a class="header-anchor" href="#spot-preemptible-instances" aria-label="Permalink to &quot;Spot/Preemptible Instances&quot;">​</a></h3><p>All four providers offer discounted instances with interruption potential:</p><ul><li><strong>Modal</strong>: Functions can be interrupted but designed for fault tolerance</li><li><strong>SimplePod</strong>: Spot pods with termination grace periods</li><li><strong>Verda</strong>: Preemptible instances with warning periods</li><li><strong>Nebius</strong>: Preemptible VMs with configurable notice</li></ul><h3 id="right-sizing-recommendations" tabindex="-1">Right-Sizing Recommendations <a class="header-anchor" href="#right-sizing-recommendations" aria-label="Permalink to &quot;Right-Sizing Recommendations&quot;">​</a></h3><p>For Nemotron 3 Super 120B NVFP4:</p><ul><li><strong>Minimum</strong>: 2x Blackwell GPUs (e.g., 2x RTX PRO 6000) for tensor parallel size 2</li><li><strong>Recommended</strong>: 4x Blackwell GPUs for better performance with tensor parallel size 4</li><li><strong>Maximum</strong>: 8x Blackwell GPUs for maximum throughput (tensor parallel size 8)</li></ul><h3 id="storage-considerations" tabindex="-1">Storage Considerations <a class="header-anchor" href="#storage-considerations" aria-label="Permalink to &quot;Storage Considerations&quot;">​</a></h3><ul><li>Model storage: ~200GB for Nemotron 3 Super NVFP4 + working space</li><li>Recommended: 500GB+ NVMe for comfortable operation</li><li>For evals/benchmarks: 1TB+ NVMe</li><li>For model development: 2TB+ NVMe+</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Select a provider below for detailed deployment instructions:</p><ul><li><a href="./modal.html">Modal</a> - Serverless platform for bursty GPU workloads</li><li><a href="./simplepod.html">SimplePod</a> - Kubernetes-based GPU provisioning</li><li><a href="./verda.html">Verda</a> - REST API for GPU instance management</li><li><a href="./nebius.html">Nebius</a> - Full cloud platform with GPU optimization</li></ul><h2 id="authentication-secrets-management" tabindex="-1">Authentication &amp; Secrets Management <a class="header-anchor" href="#authentication-secrets-management" aria-label="Permalink to &quot;Authentication &amp; Secrets Management&quot;">​</a></h2><p>Each provider requires secure handling of credentials:</p><ul><li><strong>Hugging Face Token</strong>: Read-only access for gated models like Nemotron 3 Super</li><li><strong>API Keys</strong>: Provider-specific authentication for instance provisioning</li><li><strong>SSH Keys</strong>: Optional for secure instance access</li><li><strong>Registry Credentials</strong>: For pulling Docker images from private repositories</li></ul><p>Best practices:</p><ul><li>Use provider secret management systems when available</li><li>Rotate tokens regularly</li><li>Limit permissions to minimum required</li><li>Audit access regularly</li></ul>',25)])])}const h=t(a,[["render",n]]);export{u as __pageData,h as default};
